import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';

const Learn = () => {
  const [chapters, setChapters] = useState([]);
  const [userProgress, setUserProgress] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [chaptersResponse, progressResponse] = await Promise.all([
        chaptersAPI.getAll(),
        progressAPI.getLessonProgress()
      ]);

      setChapters(chaptersResponse.data);
      setUserProgress(progressResponse.data);
    } catch (err) {
      console.error('Error fetching data:', err);
      setError('Failed to load chapters and lessons');
    } finally {
      setLoading(false);
    }
  };

  const getLessonProgress = (chapterId, lessonId) => {
    return userProgress.find(
      (progress) =>
        progress.chapterId === chapterId &&
        progress.lessonId.toString() === lessonId.toString()
    );
  };

  const handleLessonClick = (chapterId, lessonId) => {
    navigate(`/lesson/${chapterId}/${lessonId}`);
  };

  if (loading) {
    return <div className="loading">Loading chapters...</div>;
  }

  if (error) {
    return (
      <div className="container">
        <div className="error">{error}</div>
        <button className="btn btn-primary" onClick={() => navigate('/dashboard')}>
          Back to Dashboard
        </button>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="card">
        <h2>Learn Mode - Chapters & Lessons</h2>
        <p style={{ color: '#666', marginBottom: '2rem' }}>
          Progress through structured lessons to master touch typing
        </p>

        <div className="chapters-grid">
          {chapters.map((chapter) => (
            <div key={chapter._id} className="chapter-card">
              <div className="chapter-header">
                <div>
                  <h3>Chapter {chapter.chapterNumber}: {chapter.chapterTitle}</h3>
                  <p style={{ color: '#666', fontSize: '0.9rem', marginTop: '0.5rem' }}>
                    {chapter.description}
                  </p>
                </div>
                <div style={{ color: '#667eea', fontWeight: '600' }}>
                  {chapter.lessons.length} lessons
                </div>
              </div>

              <div className="lessons-list">
                {chapter.lessons.map((lesson) => {
                  const progress = getLessonProgress(chapter._id, lesson._id);

                  return (
                    <div
                      key={lesson._id}
                      className="lesson-item"
                      onClick={() => handleLessonClick(chapter._id, lesson._id)}
                    >
                      <div>
                        <strong>Lesson {lesson.lessonNumber}: {lesson.lessonTitle}</strong>
                        <div style={{ fontSize: '0.85rem', color: '#666', marginTop: '0.3rem' }}>
                          {lesson.description}
                        </div>
                        {lesson.keysIntroduced.length > 0 && (
                          <div style={{ fontSize: '0.85rem', color: '#764ba2', marginTop: '0.3rem' }}>
                            New keys: {lesson.keysIntroduced.join(', ')}
                          </div>
                        )}
                      </div>

                      {progress && (
                        <div className="lesson-progress">
                          <span>⚡ {progress.bestWPM} WPM</span>
                          <span>✓ {progress.bestAccuracy}%</span>
                          <span>🔄 {progress.attempts} attempts</span>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        <button
          className="btn btn-secondary"
          onClick={() => navigate('/dashboard')}
          style={{ marginTop: '2rem' }}
        >
          Back to Dashboard
        </button>
      </div>
    </div>
  );
};

export default Learn;
